const index = `import { Hono } from 'hono';
import { serveStatic } from 'hono/bun';
import { getAllLinks, getLinkByShortCode, createLink, incrementClickCount } from './db';
import { generateShortCode, isValidUrl, normalizeUrl } from './utils';
import { join } from 'path';

const app = new Hono();

app.use('/static/*', serveStatic({ root: './public' }));

// Home page with form
app.get('/', (c) => {
  const html = \`<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>URL Shortener</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    font-family: system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif;
    background: #f6f8fa;
    color: #1a1a1a;
    line-height: 1.6;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
  }
  header {
    background: #fff;
    border-bottom: 1px solid #e1e4e8;
    padding: 1rem 1.5rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
  }
  header a { text-decoration: none; color: inherit; }
  .logo { font-weight: 700; font-size: 1.25rem; color: #0969da; }
  nav a { margin-left: 1rem; color: #555; font-size: 0.95rem; }
  nav a:hover { color: #0969da; }
  main { flex: 1; max-width: 720px; width: 100%; margin: 3rem auto; padding: 0 1.5rem; }
  .card {
    background: #fff;
    border: 1px solid #d0d7de;
    border-radius: 12px;
    padding: 2rem;
    box-shadow: 0 1px 2px rgba(0,0,0,0.04);
  }
  h1 { font-size: 1.5rem; margin-bottom: 1.25rem; }
  form { display: flex; gap: 0.5rem; }
  input[type="url"] {
    flex: 1;
    padding: 0.65rem 0.85rem;
    border: 1px solid #d0d7de;
    border-radius: 8px;
    font-size: 1rem;
  }
  button {
    padding: 0.65rem 1.1rem;
    border: none;
    border-radius: 8px;
    background: #0969da;
    color: #fff;
    font-size: 1rem;
    cursor: pointer;
  }
  button:hover { background: #0550ae; }
  .result {
    margin-top: 1.25rem;
    padding: 1rem;
    border-radius: 8px;
    background: #ddf4ff;
    border: 1px solid #b6e3ff;
    display: none;
  }
  .result.show { display: block; }
  .result input {
    width: 100%;
    padding: 0.5rem;
    border: 1px solid #b6e3ff;
    border-radius: 6px;
    font-size: 0.95rem;
    margin-top: 0.5rem;
  }
  .error {
    margin-top: 1rem;
    padding: 0.75rem 1rem;
    border-radius: 8px;
    background: #ffebe9;
    border: 1px solid #ffc2c2;
    color: #82071e;
    display: none;
  }
  .error.show { display: block; }
  .note { margin-top: 1rem; color: #656d76; font-size: 0.9rem; }
</style>
</head>
<body>
<header>
  <a href="/" class="logo">🔗 Shortener</a>
  <nav>
    <a href="/dashboard">Dashboard</a>
  </nav>
</header>
<main>
  <div class="card">
    <h1>Shorten a link</h1>
    <form method="POST" action="/shorten">
      <input type="url" name="url" placeholder="Paste your long URL here" required />
      <button type="submit">Shorten</button>
    </form>
    <div id="error" class="error"></div>
    <p class="note">Enter a valid http:// or https:// URL to get a shareable short link.</p>
  </div>
</main>
<script>
  const params = new URLSearchParams(window.location.search);
  const short = params.get('short');
  const err = params.get('error');
  const errorBox = document.getElementById('error');
  if (err) {
    errorBox.textContent = decodeURIComponent(err);
    errorBox.classList.add('show');
  }
  if (short) {
    const card = document.querySelector('.card');
    const res = document.createElement('div');
    res.className = 'result show';
    const fullUrl = window.location.origin + '/' + encodeURIComponent(short);
    res.innerHTML = '<strong>Your short link is ready!</strong><br/>' +
      '<input id="shortLink" readonly value="' + fullUrl.replace(/&/g,'&amp;').replace(/"/g,'&quot;') + '" />';
    card.appendChild(res);
    document.getElementById('shortLink').select();
  }
</script>
</body>
</html>\`;
  return c.html(html);
});

// API + form handler to create a short link
app.post('/shorten', async (c) => {
  const body = await c.req.parseBody();
  const rawUrl = (body.url as string) || '';
  let longUrl: string;
  try {
    longUrl = normalizeUrl(rawUrl);
  } catch {
    return c.redirect('/?error=' + encodeURIComponent('Please enter a valid http:// or https:// URL.'));
  }

  let shortCode = generateShortCode();
  // Retry collision (birthday problem unlikely at small scale, but be safe)
  while (getLinkByShortCode(shortCode)) {
    shortCode = generateShortCode();
  }

  createLink(shortCode, longUrl);
  return c.redirect('/?short=' + encodeURIComponent(shortCode));
});

// JSON API to create a short link
app.post('/api/shorten', async (c) => {
  const body = await c.req.json().catch(() => ({}));
  const rawUrl = body.url || '';
  let longUrl: string;
  try {
    longUrl = normalizeUrl(rawUrl);
  } catch {
    return c.json({ error: 'Invalid URL' }, 400);
  }

  let shortCode = generateShortCode();
  while (getLinkByShortCode(shortCode)) {
    shortCode = generateShortCode();
  }

  const link = createLink(shortCode, longUrl);
  const shortUrl = new URL('/' + link.short_code, c.req.url).toString();
  return c.json({ shortCode: link.short_code, shortUrl, longUrl: link.long_url });
});

// Redirect endpoint
app.get('/:shortCode', (c) => {
  const shortCode = c.req.param('shortCode');
  const link = getLinkByShortCode(shortCode);
  if (!link) return c.notFound();

  incrementClickCount(shortCode);
  return c.redirect(link.long_url);
});

// Dashboard
app.get('/dashboard', (c) => {
  const links = getAllLinks();
  const base = new URL('/', c.req.url).toString().replace(/\\/$/, '');
  const rows = links.map(l => {
    const short = base + '/' + l.short_code;
    return \`<tr>
      <td><a href="\${short}" target="_blank">\${l.short_code}</a></td>
      <td title="\${l.long_url.replace(/"/g, '&quot;')}">\${l.long_url.length > 60 ? l.long_url.slice(0,60) + '…' : l.long_url}</td>
      <td>\${l.click_count}</td>
      <td>\${l.created_at}</td>
    </tr>\`;
  }).join('');

  const html = \`<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Dashboard – URL Shortener</title>
<style>
