import { Database } from 'bun:sqlite';
import { join } from 'path';

const dbPath = join(import.meta.dir, '..', 'data.sqlite');
export const database = new Database(dbPath);

database.exec(`
  CREATE TABLE IF NOT EXISTS links (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    short_code TEXT UNIQUE NOT NULL,
    long_url TEXT NOT NULL,
    click_count INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )
`);

export interface Link {
  id: number;
  short_code: string;
  long_url: string;
  click_count: number;
  created_at: string;
}

export function getAllLinks(): Link[] {
  return database.query('SELECT * FROM links ORDER BY created_at DESC').all() as Link[];
}

export function getLinkByShortCode(shortCode: string): Link | null {
  return database.query('SELECT * FROM links WHERE short_code = ?').get(shortCode) as Link | null;
}

export function createLink(shortCode: string, longUrl: string): Link {
  const result = database.query(
    'INSERT INTO links (short_code, long_url) VALUES (?, ?) RETURNING *'
  ).get(shortCode, longUrl) as Link;
  return result;
}

export function incrementClickCount(shortCode: string): void {
  database.query('UPDATE links SET click_count = click_count + 1 WHERE short_code = ?').run(shortCode);
}


