await daytona.write('/workspace/src/db.ts', `import { Database } from 'bun:sqlite';
import { join } from 'path';

const DB_PATH = process.env.DB_PATH || join(import.meta.dir, '..', 'data', 'shortener.db');

export interface Link {
  id: number;
  short_code: string;
  long_url: string;
  created_at: string;
  clicks: number;
}

export const database = new Database(DB_PATH, { create: true });

function getDb() {
  return new Database(DB_PATH, { create: true });
}

export function initDb(): void {
  const db = getDb();
  db.exec(\`
    CREATE TABLE IF NOT EXISTS links (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      short_code TEXT UNIQUE NOT NULL,
      long_url TEXT NOT NULL,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      clicks INTEGER NOT NULL DEFAULT 0
    )
  \`);
  db.exec('CREATE INDEX IF NOT EXISTS idx_short_code ON links(short_code)');
  db.close();
}

export function createLink(shortCode: string, longUrl: string): Link {
  const db = getDb();
  try {
    const stmt = db.prepare(
      'INSERT INTO links (short_code, long_url) VALUES (?, ?) RETURNING *'
    );
    const link = stmt.get(shortCode, longUrl) as Link;
    db.close();
    return link;
  } catch (err) {
    db.close();
    throw err;
  }
}

export function getLinkByShortCode(shortCode: string): Link | null {
  const db = getDb();
  const stmt = db.prepare('SELECT * FROM links WHERE short_code = ?');
  const link = stmt.get(shortCode) as Link | undefined;
  db.close();
  return link || null;
}

export function incrementClicks(shortCode: string): void {
  const db = getDb();
  const stmt = db.prepare('UPDATE links SET clicks = clicks + 1 WHERE short_code = ?');
  stmt.run(shortCode);
  db.close();
}

export function getAllLinks(): Link[] {
  const db = getDb();
  const stmt = db.prepare('SELECT * FROM links ORDER BY created_at DESC');
  const links = stmt.all() as Link[];
  db.close();
  return links;
}

export function shortCodeExists(shortCode: string): boolean {
  const db = getDb();
  const stmt = db.prepare('SELECT 1 FROM links WHERE short_code = ? LIMIT 1');
  const result = stmt.get(shortCode);
  db.close();
  return !!result;
}
`);

