// Create the database module
const dbCode = `import { Database } from 'bun:sqlite';

const db = new Database('/workspace/links.db');

// Create tables if they don't exist
db.exec(\`
  CREATE TABLE IF NOT EXISTS links (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    short_code TEXT UNIQUE NOT NULL,
    original_url TEXT NOT NULL,
    created_at INTEGER NOT NULL DEFAULT (unixepoch()),
    click_count INTEGER NOT NULL DEFAULT 0
  )
\`);

export interface Link {
  id: number;
  short_code: string;
  original_url: string;
  created_at: number;
  click_count: number;
}

export function createLink(shortCode: string, originalUrl: string): Link {
  const stmt = db.prepare(
    'INSERT INTO links (short_code, original_url) VALUES (?, ?) RETURNING *'
  );
  return stmt.get(shortCode, originalUrl) as Link;
}

export function getLinkByShortCode(shortCode: string): Link | null {
  const stmt = db.prepare('SELECT * FROM links WHERE short_code = ?');
  return stmt.get(shortCode) as Link | null;
}

export function incrementClickCount(shortCode: string): void {
  const stmt = db.prepare(
    'UPDATE links SET click_count = click_count + 1 WHERE short_code = ?'
  );
  stmt.run(shortCode);
}

export function getAllLinks(): Link[] {
  const stmt = db.prepare('SELECT * FROM links ORDER BY created_at DESC');
  return stmt.all() as Link[];
}

export function deleteLink(shortCode: string): boolean {
  const stmt = db.prepare('DELETE FROM links WHERE short_code = ?');
  const result = stmt.run(shortCode);
  return result.changes > 0;
}

export { db };
`;

