const server = serve({
  port: 3000,
  async fetch(req) {
    const url = new URL(req.url);
    const baseUrl = \`\${url.protocol}//\${url.host}\`;

    // API: create short link
    if (url.pathname === "/api/shorten" && req.method === "POST") {
      try {
        const body = await req.json();
        const originalUrl = body?.url?.trim();
        if (!originalUrl) {
          return new Response(JSON.stringify({ error: "URL is required" }), {
            status: 400,
            headers: { "Content-Type": "application/json" },
          });
        }

        let shortCode = generateShortCode();
        // Simple collision avoidance
        while (getLinkByShortCode(shortCode)) {
          shortCode = generateShortCode();
        }

        createLink(shortCode, originalUrl);
        const shortUrl = \`\${baseUrl}/\${shortCode}\`;
        return new Response(JSON.stringify({ shortUrl, shortCode }), {
          headers: { "Content-Type": "application/json" },
        });
      } catch (err) {
        return new Response(JSON.stringify({ error: "Invalid request" }), {
          status: 400,
          headers: { "Content-Type": "application/json" },
        });
      }
    }

    // Dashboard
    if (url.pathname === "/dashboard") {
      const links = getAllLinks();
      return new Response(htmlDashboard(links, baseUrl), {
        headers: { "Content-Type": "text/html" },
      });
    }

    // Home page
    if (url.pathname === "/") {
      return new Response(htmlHome, {
        headers: { "Content-Type": "text/html" },
      });
    }

    // Redirect short links
    const shortCode = url.pathname.slice(1);
    if (shortCode && !shortCode.includes("/")) {
      const link = getLinkByShortCode(shortCode);
      if (link) {
        incrementClickCount(shortCode);
        return Response.redirect(link.original_url, 302);
      }
    }

    return new Response("Not Found", { status: 404 });
  },
});

console.log(\`Server running at http://localhost:\${server.port}\`);
