          const existing = db.query("SELECT id FROM links WHERE short_code = ?").get(shortCode);
          if (!existing) break;
          shortCode = generateShortCode();
          attempts++;
        }

        db.run("INSERT INTO links (original_url, short_code) VALUES (?, ?)", [originalUrl, shortCode]);

        const shortUrl = \`http://localhost:3000/\${shortCode}\`;
        return new Response(JSON.stringify({ shortCode, shortUrl }), {
          headers: { ...headers, "Content-Type": "application/json" },
        });
      } catch (err) {
        return new Response(JSON.stringify({ error: "Internal server error" }), {
          status: 500,
          headers: { ...headers, "Content-Type": "application/json" },
        });
      }
    }

    if (path === "/api/links" && method === "GET") {
      const links = db
        .query("SELECT original_url, short_code, clicks, created_at FROM links ORDER BY created_at DESC")
        .all();
      const result = links.map((row: any) => ({
        originalUrl: row.original_url,
        shortCode: row.short_code,
        shortUrl: \`http://localhost:3000/\${row.short_code}\`,
        clicks: row.clicks,
        createdAt: row.created_at,
      }));
      return new Response(JSON.stringify(result), {
        headers: { ...headers, "Content-Type": "application/json" },
      });
    }

    // Short link redirect
    const match = path.match(/^\\/([a-zA-Z0-9]{6})$/);
    if (match && method === "GET") {
      const shortCode = match[1];
      const row = db.query("SELECT original_url FROM links WHERE short_code = ?").get(shortCode) as any;
      if (row) {
        db.run("UPDATE links SET clicks = clicks + 1 WHERE short_code = ?", [shortCode]);
        return Response.redirect(row.original_url, 302);
      }
    }

    return new Response("Not Found", { status: 404, headers });
  },
});

