serve({
  port: 3000,
  async fetch(req) {
    const url = new URL(req.url);
    const path = url.pathname;
    const method = req.method;

    // CORS headers for all responses
    const headers = {
      "Access-Control-Allow-Origin": "*",
      "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
      "Access-Control-Allow-Headers": "Content-Type",
    };

    if (method === "OPTIONS") {
      return new Response(null, { status: 204, headers });
    }

    if (path === "/" && method === "GET") {
      return new Response(HTML, {
        headers: { ...headers, "Content-Type": "text/html" },
      });
    }

    if (path === "/api/shorten" && method === "POST") {
      try {
        const body = await req.json();
        const originalUrl = body?.url?.trim();

        if (!originalUrl) {
          return new Response(JSON.stringify({ error: "URL is required" }), {
            status: 400,
            headers: { ...headers, "Content-Type": "application/json" },
          });
        }

        if (!isValidUrl(originalUrl)) {
          return new Response(JSON.stringify({ error: "Invalid URL format" }), {
            status: 400,
            headers: { ...headers, "Content-Type": "application/json" },
          });
        }

        let shortCode = generateShortCode();
        let attempts = 0;
        while (attempts < 10) {
          const existing = db.query("SELECT id FROM links WHERE short_code = ?").get(shortCode);
          if (!existing) break;
          shortCode = generateShortCode();
          attempts++;
        }

        db.run("INSERT INTO links (original_url, short_code) VALUES (?, ?)", [originalUrl, shortCode]);

        const shortUrl = \`http://localhost:3000/\${shortCode}\`;
        return new Response(JSON.stringify({ shortCode, shortUrl }), {
          headers: { ...headers, "Content-Type": "application/json" },
        });
      } catch (err) {
        return new Response(JSON.stringify({ error: "Internal server error" }), {
          status: 500,
          headers: { ...headers, "Content-Type": "application/json" },
        });
      }
    }

    if (path === "/api/links" && method === "GET") {
      const links = db
        .query("SELECT original_url, short_code, clicks, created_at FROM links ORDER BY created_at DESC")
        .all();
      const result = links.map((row: any) => ({
        originalUrl: row.original_url,
        shortCode: row.short_code,
        shortUrl: \`http://localhost:3000/\${row.short_code}\`,
        clicks: row.clicks,
        createdAt: row.created_at,
      }));
      return new Response(JSON.stringify(result), {
        headers: { ...headers, "Content-Type": "application/json" },
      });
    }

