    expect(data.shortCode).toBeDefined();
    expect(data.shortUrl).toContain(data.shortCode);
    expect(data.originalUrl).toBe("https://example.com");
  });

  it("should reject missing URL", async () => {
    const res = await fetchLocal("/api/shorten", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({}),
    });
    expect(res.status).toBe(400);
  });

  it("should reject invalid URL", async () => {
    const res = await fetchLocal("/api/shorten", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ url: "not-a-url" }),
    });
    expect(res.status).toBe(400);
  });

  it("should redirect and track clicks", async () => {
    const shortenRes = await fetchLocal("/api/shorten", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ url: "https://example.com/path" }),
    });
    const { shortCode } = await shortenRes.json();

    const redirectRes = await fetchLocal(`/${shortCode}`);
    expect(redirectRes.status).toBe(302);
    expect(redirectRes.headers.get("location")).toBe("https://example.com/path");

    const listRes = await fetchLocal("/api/links");
    const data = await listRes.json();
    const link = data.links.find((l: any) => l.short_code === shortCode);
    expect(link).toBeDefined();
    expect(link.clicks).toBe(1);
  });

  it("should return 404 for unknown short code", async () => {
    const res = await fetchLocal("/unknown123");
    expect(res.status).toBe(404);
  });

  it("should add https if missing", async () => {
    const res = await fetchLocal("/api/shorten", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ url: "example.com" }),
    });
    expect(res.status).toBe(201);
    const data = await res.json();
    expect(data.originalUrl).toBe("https://example.com");
  });
});
