Database module (`src/db.ts`):
```ts
import { Database } from "bun:sqlite";

const dbPath = process.env.DATABASE_URL || "urls.sqlite";
export const db = new Database(dbPath);

db.exec(`
  CREATE TABLE IF NOT EXISTS links (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    short_code TEXT UNIQUE NOT NULL,
    original_url TEXT NOT NULL,
    clicks INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );
`);

export function createLink(originalUrl: string): { shortCode: string } {
  let shortCode = generateShortCode();
  // In case of collision, retry a few times
  for (let i = 0; i < 5; i++) {
    try {
      db.prepare("INSERT INTO links (short_code, original_url) VALUES (?, ?)").run(shortCode, originalUrl);
      return { shortCode };
    } catch (e: any) {
      if (e.message.includes("UNIQUE constraint failed")) {
        shortCode = generateShortCode();
        continue;
      }
      throw e;
    }
  }
  throw new Error("Failed to generate unique short code");
}

export function getLink(shortCode: string) {
  return db.prepare("SELECT * FROM links WHERE short_code = ?").get(shortCode) as
    | { id: number; short_code: string; original_url: string; clicks: number; created_at: string }
    | undefined;
}

export function incrementClicks(shortCode: string) {
  db.prepare("UPDATE links SET clicks = clicks + 1 WHERE short_code = ?").run(shortCode);
}

export function getAllLinks() {
  return db.prepare("SELECT * FROM links ORDER BY created_at DESC").all() as
    { id: number; short_code: string; original_url: string; clicks: number; created_at: string }[];
}

function generateShortCode(): string {
  const chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
  let result = "";
  const randomValues = new Uint8Array(6);
  crypto.getRandomValues(randomValues);
  for (let i = 0; i < 6; i++) {
    result += chars[randomValues[i] % chars.length];
  }
  return result;
}
```

Server module (`src/server.ts`):
```ts
import { db, createLink, getLink, incrementClicks, getAllLinks } from "./db";

export async function handleRequest(req: Request): Promise<Response> {
  const url = new URL(req.url);
  const pathname = url.pathname;

  // CORS
  const corsHeaders = {
    "Access-Control-Allow-Origin": "*",
    "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
    "Access-Control-Allow-Headers": "Content-Type",
  };

  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  // API routes
  if (pathname === "/api/shorten" && req.method === "POST") {
    try {
      const body = await req.json();
      const originalUrl = body?.url;
      if (!originalUrl || typeof originalUrl !== "string") {
        return jsonResponse({ error: "URL is required" }, 400);
      }
      // Basic URL validation
      let validatedUrl = originalUrl.trim();
      if (!/^https?:\/\//i.test(validatedUrl)) {
        validatedUrl = "https://" + validatedUrl;
      }
      // Try to construct URL
      try {
        new URL(validatedUrl);
      } catch {
        return jsonResponse({ error: "Invalid URL" }, 400);
      }
      const { shortCode } = createLink(validatedUrl);
      const shortUrl = `${url.origin}/${shortCode}`;
      return jsonResponse({ success: true, shortCode, shortUrl, originalUrl: validatedUrl }, 201);
    } catch (e) {
      return jsonResponse({ error: "Failed to shorten URL" }, 500);
    }
  }

  if (pathname === "/api/links" && req.method === "GET") {
    const links = getAllLinks();
    return jsonResponse({ links });
  }

  // Static files
  if (pathname === "/" || pathname === "/index.html") {
    return serveFile("src/public/index.html", "text/html");
  }
  if (pathname === "/style.css") {
    return serveFile("src/public/style.css", "text/css");
  }
  if (pathname === "/app.js") {
    return serveFile("src/public/app.js", "application/javascript");
  }

  // Short link redirect
  if (pathname.length > 1 && req.method === "GET") {
    const shortCode = pathname.slice(1);
    const link = getLink(shortCode);
    if (link) {
      incrementClicks(shortCode);
      return Response.redirect(link.original_url, 302);
    }
  }

  return new Response("Not Found", { status: 404 });

  function jsonResponse(data: any, status = 200) {
    return new Response(JSON.stringify(data), {
      status,
      headers: { "Content-Type": "application/json", ...corsHeaders },
    });
  }

  async function serveFile(filePath: string, contentType: string) {
    try {
      const file = Bun.file(filePath);
      if (!(await file.exists())) {
        return new Response("Not Found", { status: 404 });
      }
      return new Response(file, { headers: { "Content-Type": contentType } });
    } catch {
      return new Response("Not Found", { status: 404 });
    }
  }
}

if (import.meta.main) {
  const port = Number(process.env.PORT || 3000);
  Bun.serve({ port, fetch: handleRequest });
  console.log(`Server running on http://localhost:${port}`);
}
```

