JS (`src/public/app.js`):
```js
const form = document.getElementById('shorten-form');
const urlInput = document.getElementById('url-input');
const resultDiv = document.getElementById('result');
const shortLink = document.getElementById('short-link');
const copyBtn = document.getElementById('copy-btn');
const errorDiv = document.getElementById('error');
const tbody = document.getElementById('links-tbody');

form.addEventListener('submit', async (e) => {
  e.preventDefault();
  hide(resultDiv);
  hide(errorDiv);
  const url = urlInput.value.trim();
  if (!url) return;

  try {
    const res = await fetch('/api/shorten', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ url }),
    });
    const data = await res.json();
    if (!res.ok) {
      showError(data.error || 'Something went wrong');
      return;
    }
    shortLink.href = data.shortUrl;
    shortLink.textContent = data.shortUrl;
    show(resultDiv);
    urlInput.value = '';
    loadDashboard();
  } catch (err) {
    showError('Network error. Please try again.');
  }
});

copyBtn.addEventListener('click', () => {
  navigator.clipboard.writeText(shortLink.href).then(() => {
    copyBtn.textContent = 'Copied!';
    setTimeout(() => copyBtn.textContent = 'Copy', 1500);
  });
});

async function loadDashboard() {
  try {
    const res = await fetch('/api/links');
    const data = await res.json();
    renderTable(data.links || []);
  } catch (err) {
    console.error('Failed to load dashboard', err);
  }
}

function renderTable(links) {
  tbody.innerHTML = '';
  if (links.length === 0) {
    tbody.innerHTML = '<tr class="empty-row"><td colspan="4">No links yet. Create one above!</td></tr>';
    return;
  }
  for (const link of links) {
    const tr = document.createElement('tr');
    const shortUrl = `${window.location.origin}/${link.short_code}`;
    tr.innerHTML = `
      <td><a href="${shortUrl}" target="_blank">${shortUrl}</a></td>
      <td title="${escapeHtml(link.original_url)}">${escapeHtml(truncate(link.original_url, 50))}</td>
      <td>${link.clicks}</td>
      <td>${new Date(link.created_at).toLocaleString()}</td>
    `;
    tbody.appendChild(tr);
  }
}

function truncate(str, n) {
  return str.length > n ? str.slice(0, n) + '…' : str;
}

function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
}

function show(el) { el.classList.remove('hidden'); }
function hide(el) { el.classList.add('hidden'); }
function showError(msg) {
  errorDiv.textContent = msg;
  show(errorDiv);
}

loadDashboard();
```

