  it("increments clicks", () => {
    db.query("INSERT INTO links (slug, url) VALUES (?, ?)").run("xyz789", "https://example.com");
    db.query("UPDATE links SET clicks = clicks + 1 WHERE slug = ?").run("xyz789");
    const row = db.query("SELECT clicks FROM links WHERE slug = ?").get("xyz789") as any;
    expect(row.clicks).toBe(1);
