function homePage(resultSlug?: string, error?: string): Response {
  let body = \`
    <div class="card">
      <form method="POST" action="/shorten" class="form-group">
        <input type="url" name="url" placeholder="Paste a long URL (https://...)" required />
        <button type="submit">Shorten</button>
      </form>
  \`;
  if (error) {
    body += \`<div class="error">\${escapeHtml(error)}</div>\`;
  }
  if (resultSlug) {
    const shortUrl = \`\${BASE_URL}/\${resultSlug}\`;
    body += \`
      <div class="result show">
        <strong>Your short link:</strong><br>
        <a href="\${escapeHtml(shortUrl)}" target="_blank">\${escapeHtml(shortUrl)}</a>
      </div>
    \`;
  }
  body += "</div>";
  return new Response(HTML_HEAD + body + HTML_FOOT, {
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });
}

function dashboardPage(): Response {
  const rows = db.query("SELECT slug, url, clicks, created_at FROM links ORDER BY created_at DESC").all() as any[];

  let body = '<div class="card"><h2 style="margin-top:0">Dashboard</h2>';
  if (rows.length === 0) {
    body += '<div class="empty-state">No links yet. <a href="/">Create one!</a></div>';
  } else {
    body += '<table><thead><tr><th>Short Link</th><th>Original URL</th><th>Clicks</th><th>Created</th></tr></thead><tbody>';
    for (const row of rows) {
      const shortUrl = \`\${BASE_URL}/\${row.slug}\`;
      body += \`
        <tr>
          <td><a href="\${escapeHtml(shortUrl)}" target="_blank">\${escapeHtml(row.slug)}</a></td>
          <td class="url-cell" title="\${escapeHtml(row.url)}"><a href="\${escapeHtml(row.url)}" target="_blank">\${escapeHtml(row.url)}</a></td>
          <td>\${row.clicks}</td>
          <td>\${escapeHtml(row.created_at)}</td>
        </tr>
      \`;
    }
    body += "</tbody></table>";
  }
  body += "</div>";
  return new Response(HTML_HEAD + body + HTML_FOOT, {
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

const PORT = Number(process.env.PORT) || 3000;
const BASE_URL = process.env.BASE_URL || \`http://localhost:\${PORT}\`;

const server = serve({
  port: PORT,
  async fetch(req) {
    const url = new URL(req.url);
    const pathname = url.pathname;

    if (req.method === "GET" && pathname === "/") {
      return homePage();
    }

    if (req.method === "GET" && pathname === "/dashboard") {
      return dashboardPage();
    }

    if (req.method === "POST" && pathname === "/shorten") {
      const form = await req.formData();
      const longUrl = form.get("url")?.toString().trim() || "";

      if (!longUrl) {
        return homePage(undefined, "Please enter a URL.");
      }
      if (!isValidUrl(longUrl)) {
        return homePage(undefined, "Please enter a valid http:// or https:// URL.");
      }

      let slug = generateSlug();
      let attempts = 0;
      while (attempts < 10) {
        try {
          db.query("INSERT INTO links (slug, url) VALUES (?, ?)").run(slug, longUrl);
          break;
        } catch (e: any) {
          if (e.message?.includes("UNIQUE constraint failed")) {
            slug = generateSlug();
            attempts++;
          } else {
            throw e;
          }
        }
      }
      if (attempts >= 10) {
        return homePage(undefined, "Could not generate a unique slug. Please try again.");
      }

      return homePage(slug);
    }

    if (req.method === "GET") {
      const slug = pathname.slice(1);
      if (slug && !slug.includes("/")) {
        const row = db.query("SELECT url FROM links WHERE slug = ?").get(slug) as { url: string } | undefined;
        if (row) {
          db.query("UPDATE links SET clicks = clicks + 1 WHERE slug = ?").run(slug);
          return Response.redirect(row.url, 302);
        }
      }
    }

    return new Response("Not Found", { status: 404 });
  },
});

console.log(\`Server running at \${BASE_URL}\`);
`;

