    expect(isValidUrl("http://example.com")).toBe(true);
  });
  it("accepts https URLs", () => {
    expect(isValidUrl("https://example.com/path?query=1")).toBe(true);
  });
  it("rejects javascript: URLs", () => {
    expect(isValidUrl("javascript:alert(1)")).toBe(false);
  });
  it("rejects data: URLs", () => {
    expect(isValidUrl("data:text/html,<script>alert(1)</script>")).toBe(false);
  });
  it("rejects relative URLs", () => {
    expect(isValidUrl("/foo/bar")).toBe(false);
  });
  it("rejects empty strings", () => {
    expect(isValidUrl("")).toBe(false);
  });
  it("rejects ftp URLs", () => {
    expect(isValidUrl("ftp://example.com")).toBe(false);
  });
});

describe("database", () => {
  beforeEach(() => {
    db.exec("DELETE FROM links");
  });

  it("inserts and retrieves a link", () => {
    db.query("INSERT INTO links (slug, url) VALUES (?, ?)").run("abc123", "https://example.com");
    const row = db.query("SELECT url, clicks FROM links WHERE slug = ?").get("abc123") as any;
    expect(row.url).toBe("https://example.com");
    expect(row.clicks).toBe(0);
  });

  it("increments clicks", () => {
    db.query("INSERT INTO links (slug, url) VALUES (?, ?)").run("xyz789", "https://example.com");
    db.query("UPDATE links SET clicks = clicks + 1 WHERE slug = ?").run("xyz789");
    const row = db.query("SELECT clicks FROM links WHERE slug = ?").get("xyz789") as any;
    expect(row.clicks).toBe(1);
  });

  it("enforces unique slug constraint", () => {
    db.query("INSERT INTO links (slug, url) VALUES (?, ?)").run("dup", "https://a.com");
    expect(() => {
      db.query("INSERT INTO links (slug, url) VALUES (?, ?)").run("dup", "https://b.com");
    }).toThrow();
  });
});

afterAll(() => {
  db.close();
  try { unlinkSync(TEST_DB); } catch {}
});
