  CREATE TABLE IF NOT EXISTS links (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    short_code TEXT UNIQUE NOT NULL,
    long_url TEXT NOT NULL,
    clicks INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )
\`);

export interface Link {
  id: number;
  short_code: string;
  long_url: string;
  clicks: number;
  created_at: string;
}

export function createLink(longUrl: string, shortCode?: string): Link {
  const code = shortCode || generateShortCode();
  const stmt = db.prepare("INSERT INTO links (short_code, long_url) VALUES (?, ?) RETURNING *");
  return stmt.get(code, longUrl) as Link;
}

export function getLinkByShortCode(shortCode: string): Link | null {
  const stmt = db.prepare("SELECT * FROM links WHERE short_code = ?");
  return stmt.get(shortCode) as Link | null;
}

export function incrementClicks(shortCode: string): void {
  const stmt = db.prepare("UPDATE links SET clicks = clicks + 1 WHERE short_code = ?");
  stmt.run(shortCode);
}

export function getAllLinks(): Link[] {
  const stmt = db.prepare("SELECT * FROM links ORDER BY created_at DESC");
  return stmt.all() as Link[];
}

function generateShortCode(): string {
  const chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
  let result = "";
  for (let i = 0; i < 6; i++) {
    result += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  // Check for collision and retry if needed
  const existing = getLinkByShortCode(result);
  if (existing) {
    return generateShortCode();
  }
  return result;
}

export { db };
