  <div class="container">
    <h1>Link Shortener</h1>
    <p class="subtitle">Paste a long URL to get a short, shareable link</p>

    <div class="card">
      <div class="input-group">
        <input type="url" id="urlInput" placeholder="https://example.com/very/long/url" required>
        <button id="shortenBtn" onclick="shorten()">Shorten</button>
      </div>
      <div id="error" class="error" style="display:none"></div>
      <div id="result" class="result">
        <p>Here's your short link:</p>
        <a id="shortLink" href="#" target="_blank"></a>
        <button class="copy-btn" onclick="copyLink()" style="margin-left: 12px;">Copy</button>
      </div>
    </div>

    <div class="card">
      <h2 style="margin-bottom: 16px; font-size: 1.25rem;">Your Links</h2>
