    const urlInput = document.getElementById('urlInput');
    const shortenBtn = document.getElementById('shortenBtn');
    const result = document.getElementById('result');
    const shortLink = document.getElementById('shortLink');
    const error = document.getElementById('error');
    const linksTable = document.getElementById('linksTable');

    urlInput.addEventListener('keypress', (e) => { if (e.key === 'Enter') shorten(); });

    async function shorten() {
      const url = urlInput.value.trim();
      if (!url) return;

      error.style.display = 'none';
      shortenBtn.disabled = true;
      shortenBtn.textContent = 'Shortening...';

      try {
        const res = await fetch('/api/shorten', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ url })
        });
        const data = await res.json();

        if (!res.ok) {
          throw new Error(data.error || 'Something went wrong');
        }

        const shortUrl = `${window.location.origin}/${data.shortCode}`;
        shortLink.href = shortUrl;
        shortLink.textContent = shortUrl;
        result.classList.add('show');
        urlInput.value = '';
        loadLinks();
      } catch (err) {
        error.textContent = err.message;
        error.style.display = 'block';
      } finally {
        shortenBtn.disabled = false;
        shortenBtn.textContent = 'Shorten';
      }
    }

    function copyLink() {
      navigator.clipboard.writeText(shortLink.href);
      const btn = document.querySelector('#result .copy-btn');
      btn.textContent = 'Copied!';
      setTimeout(() => btn.textContent = 'Copy', 2000);
    }

    async function loadLinks() {
      try {
        const res = await fetch('/api/links');
        const links = await res.json();

        if (links.length === 0) {
          linksTable.innerHTML = '<div class="empty">No links created yet</div>';
          return;
        }

        linksTable.innerHTML = `
          <table>
            <thead>
              <tr>
                <th>Short Link</th>
                <th>Original URL</th>
                <th>Clicks</th>
                <th></th>
              </tr>
            </thead>
            <tbody>
              ${links.map(link => {
                const shortUrl = `${window.location.origin}/${link.short_code}`;
                return `
                  <tr>
                    <td><a href="${shortUrl}" target="_blank">/${link.short_code}</a></td>
                    <td class="url-cell" title="${link.original_url}">${link.original_url}</td>
                    <td class="clicks">${link.clicks}</td>
                    <td><button class="copy-btn" onclick="navigator.clipboard.writeText('${shortUrl}')">Copy</button></td>
                  </tr>
                `;
              }).join('')}
            </tbody>
          </table>
        `;
      } catch (err) {
        console.error('Failed to load links', err);
      }
    }

    loadLinks();
  </script>
</body>
</html>
