      <div id="error" class="error" style="display:none"></div>
      <div id="result" class="result">
        <p>Here's your short link:</p>
        <a id="shortLink" href="#" target="_blank"></a>
        <button class="copy-btn" onclick="copyLink()" style="margin-left: 12px;">Copy</button>
      </div>
    </div>

    <div class="card">
      <h2 style="margin-bottom: 16px; font-size: 1.25rem;">Your Links</h2>
      <div id="linksTable">
        <div class="empty">No links created yet</div>
      </div>
    </div>
