      btn.textContent = 'Copied!';
      setTimeout(() => btn.textContent = 'Copy', 2000);
    }

    async function loadLinks() {
      try {
        const res = await fetch('/api/links');
        const links = await res.json();

        if (links.length === 0) {
          linksTable.innerHTML = '<div class="empty">No links created yet</div>';
          return;
        }

        linksTable.innerHTML = \`
          <table>
            <thead>
              <tr>
                <th>Short Link</th>
                <th>Original URL</th>
                <th>Clicks</th>
                <th>Created</th>
                <th></th>
              </tr>
            </thead>
            <tbody>
              \${links.map(link => {
                const shortUrl = \`\${window.location.origin}/\${link.short_code}\`;
                const date = new Date(link.created_at).toLocaleDateString();
                return \`
                  <tr>
                    <td><a href="\${shortUrl}" target="_blank">/\${link.short_code}</a></td>
                    <td class="url-cell" title="\${link.original_url}">\${link.original_url}</td>
                    <td class="clicks">\${link.clicks}</td>
                    <td>\${date}</td>
