db.ts:
```ts
import { Database } from "bun:sqlite";

const db = new Database("urls.db");

db.run(`
  CREATE TABLE IF NOT EXISTS links (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    short_code TEXT UNIQUE NOT NULL,
    original_url TEXT NOT NULL,
    clicks INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )
`);

export function createLink(originalUrl: string): string {
  const shortCode = generateShortCode();
  try {
    db.query("INSERT INTO links (short_code, original_url) VALUES (?, ?)").run(shortCode, originalUrl);
    return shortCode;
  } catch (e: any) {
    if (e.message.includes("UNIQUE constraint failed")) {
      return createLink(originalUrl); // retry
    }
    throw e;
  }
}

export function getLink(shortCode: string) {
  return db.query("SELECT * FROM links WHERE short_code = ?").get(shortCode) as any;
}

export function incrementClicks(shortCode: string) {
  db.query("UPDATE links SET clicks = clicks + 1 WHERE short_code = ?").run(shortCode);
}

export function getAllLinks() {
  return db.query("SELECT short_code, original_url, clicks, created_at FROM links ORDER BY created_at DESC").all() as any[];
}

function generateShortCode(): string {
  const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let result = '';
  for (let i = 0; i < 6; i++) {
    result += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return result;
}
