await daytona.write("/workspace/db.ts", `import { Database } from "bun:sqlite";

let db: Database;

export function initDatabase(path: string = "urls.db") {
  db = new Database(path);
  db.run(\`
    CREATE TABLE IF NOT EXISTS links (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      short_code TEXT UNIQUE NOT NULL,
      original_url TEXT NOT NULL,
      clicks INTEGER DEFAULT 0,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )
  \`);
}

export function createLink(originalUrl: string): string {
  const shortCode = generateShortCode();
  try {
    db.query("INSERT INTO links (short_code, original_url) VALUES (?, ?)").run(shortCode, originalUrl);
    return shortCode;
  } catch (e: any) {
    if (e.message?.includes("UNIQUE constraint failed")) {
      return createLink(originalUrl);
    }
    throw e;
  }
}

export function getLink(shortCode: string) {
  return db.query("SELECT * FROM links WHERE short_code = ?").get(shortCode) as {
    id: number;
    short_code: string;
    original_url: string;
    clicks: number;
    created_at: string;
  } | null;
}

export function incrementClicks(shortCode: string): void {
  db.query("UPDATE links SET clicks = clicks + 1 WHERE short_code = ?").run(shortCode);
}

export function getAllLinks() {
  return db.query("SELECT short_code, original_url, clicks, created_at FROM links ORDER BY created_at DESC").all() as {
    short_code: string;
    original_url: string;
    clicks: number;
    created_at: string;
  }[];
}

function generateShortCode(): string {
  const chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
  let result = "";
  for (let i = 0; i < 6; i++) {
    result += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return result;
}
`);

await daytona.write("/workspace/server.ts", `import { initDatabase, createLink, getLink, incrementClicks, getAllLinks } from "./db";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
  "Access-Control-Allow-Headers": "Content-Type",
};

export async function handleRequest(req: Request): Promise<Response> {
  const url = new URL(req.url);
  const pathname = url.pathname;

  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  if (pathname === "/api/shorten" && req.method === "POST") {
    try {
      const body = await req.json();
      const originalUrl = body?.url;

      if (!originalUrl || !isValidUrl(originalUrl)) {
        return jsonResponse({ error: "Invalid URL" }, 400);
      }

      const shortCode = createLink(originalUrl);
      return jsonResponse({ shortCode, originalUrl });
    } catch (err: any) {
      return jsonResponse({ error: err.message || "Failed to create link" }, 500);
    }
  }

  if (pathname === "/api/links" && req.method === "GET") {
    try {
      const links = getAllLinks();
      return jsonResponse(links);
    } catch (err: any) {
      return jsonResponse({ error: err.message || "Failed to fetch links" }, 500);
    }
  }

  if (pathname === "/" && req.method === "GET") {
    const file = Bun.file("public/index.html");
    return new Response(file, { headers: { "Content-Type": "text/html" } });
  }

  if (pathname.length > 1 && req.method === "GET" && !pathname.includes(".")) {
    const shortCode = pathname.slice(1);
    const link = getLink(shortCode);
    if (link) {
      incrementClicks(shortCode);
      return Response.redirect(link.original_url, 302);
    }
  }

  return new Response("Not Found", { status: 404 });
}

function jsonResponse(body: object, status: number = 200): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: {
      "Content-Type": "application/json",
      ...corsHeaders,
    },
  });
}

function isValidUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    return parsed.protocol === "http:" || parsed.protocol === "https:";
  } catch {
    return false;
  }
}

function start() {
  initDatabase();
  const port = Number(process.env.PORT) || 3000;
  Bun.serve({
    port,
    fetch: handleRequest,
  });
  console.log(\`Server running at http://localhost:\${port}\`);
}

if (import.meta.main) {
  start();
}
`);

