    const code = createLink("https://example.com");
    incrementClicks(code);
    const link = getLink(code);
    expect(link?.clicks).toBe(1);
  });

  it("should return all links ordered by created_at desc", () => {
    createLink("https://first.com");
    createLink("https://second.com");
    const links = getAllLinks();
    expect(links.length).toBe(2);
  });
});

describe("API", () => {
