    initDatabase(":memory:");
  });

  it("should shorten a valid URL", async () => {
    const req = new Request("http://localhost/api/shorten", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ url: "https://example.com" }),
    });
    const res = await handleRequest(req);
    expect(res.status).toBe(200);
    const data = await res.json();
    expect(data.shortCode).toBeString();
  });

  it("should reject invalid URLs", async () => {
    const req = new Request("http://localhost/api/shorten", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ url: "not-a-url" }),
    });
    const res = await handleRequest(req);
    expect(res.status).toBe(400);
  });

  it("should reject javascript URLs", async () => {
    const req = new Request("http://localhost/api/shorten", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ url: "javascript:alert(1)" }),
    });
    const res = await handleRequest(req);
    expect(res.status).toBe(400);
  });

  it("should redirect existing short links", async () => {
    const code = createLink("https://example.com");
    const req = new Request(`http://localhost/${code}`);
    const res = await handleRequest(req);
    expect(res.status).toBe(302);
    expect(res.headers.get("location")).toBe("https://example.com");
  });

  it("should return 404 for unknown short links", async () => {
    const req = new Request("http://localhost/unknown");
    const res = await handleRequest(req);
    expect(res.status).toBe(404);
  });

  it("should list links", async () => {
    createLink("https://example.com");
    const req = new Request("http://localhost/api/links");
    const res = await handleRequest(req);
    expect(res.status).toBe(200);
    const data = await res.json();
    expect(data.length).toBe(1);
  });

