async function writeFile(path, content) {
  const escaped = content.replace(/'/g, "'\"'\"'");
  const { stdout, stderr, exitCode } = await daytona.exec(`cat > ${path} << 'EOF'\n${content}\nEOF`);
  if (exitCode !== 0) throw new Error(`Failed to write ${path}: ${stderr}`);
}

