const serverCode = `import { createLink, getLink, incrementClicks, getAllLinks } from "./db";

const PORT = process.env.PORT || 3000;
const HOST = process.env.HOST || "http://localhost";

function renderTable(): string {
  const links = getAllLinks();
  if (links.length === 0) {
    return '<div class="empty">No links yet. Create one above!</div>';
  }
  const baseUrl = \`\${HOST}:\${PORT}\`;
  let rows = links.map(l => \`
    <tr>
      <td><a href="\${baseUrl}/\${l.short_code}" target="_blank">\${baseUrl}/\${l.short_code}</a></td>
      <td class="url-cell" title="\${l.long_url}">\${l.long_url}</td>
      <td><span class="badge">\${l.clicks}</span></td>
      <td>\${new Date(l.created_at).toLocaleDateString()} \${new Date(l.created_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</td>
    </tr>
  \`).join('');
  return \`
    <table>
      <thead>
        <tr><th>Short Link</th><th>Original URL</th><th>Clicks</th><th>Created</th></tr>
      </thead>
      <tbody>\${rows}</tbody>
    </table>
  \`;
}

async function readTemplate(): Promise<string> {
  const file = Bun.file("template.html");
  let text = await file.text();
  return text.replace("{{LINKS_TABLE}}", renderTable());
}

const server = Bun.serve({
  port: PORT,
  async fetch(req) {
    const url = new URL(req.url);
    const path = url.pathname;

    // API: shorten
    if (path === "/api/shorten" && req.method === "POST") {
      try {
        const body = await req.json();
        const longUrl = body?.url;
        if (!longUrl || typeof longUrl !== "string") {
          return new Response(JSON.stringify({ error: "URL is required" }), { status: 400, headers: { "Content-Type": "application/json" } });
        }
        let validUrl = longUrl;
        if (!/^https?:\\/\\//i.test(validUrl)) {
          validUrl = "https://" + validUrl;
        }
        try { new URL(validUrl); } catch {
          return new Response(JSON.stringify({ error: "Invalid URL" }), { status: 400, headers: { "Content-Type": "application/json" } });
        }
        const code = createLink(validUrl);
        const shortUrl = \`\${HOST}:\${PORT}/\${code}\`;
        return new Response(JSON.stringify({ shortUrl, code }), { headers: { "Content-Type": "application/json" } });
      } catch {
        return new Response(JSON.stringify({ error: "Bad request" }), { status: 400, headers: { "Content-Type": "application/json" } });
      }
    }

    // API: list links
    if (path === "/api/links" && req.method === "GET") {
      const links = getAllLinks();
      const baseUrl = \`\${HOST}:\${PORT}\`;
      return new Response(JSON.stringify(links.map(l => ({ ...l, shortUrl: \`\${baseUrl}/\${l.short_code}\` }))), { headers: { "Content-Type": "application/json" } });
    }

    // Redirect short link
    if (path.startsWith("/") && path.length > 1 && !path.includes(".") && !path.startsWith("/api/")) {
      const code = path.slice(1);
      const link = getLink(code);
      if (link) {
        incrementClicks(code);
        return Response.redirect(link.long_url, 302);
      }
    }

    // Home page
    if (path === "/") {
      const html = await readTemplate();
      return new Response(html, { headers: { "Content-Type": "text/html" } });
    }

    return new Response("Not found", { status: 404 });
  },
});

console.log(\`Server running at http://localhost:\${server.port}\`);
`;

