// Create database module
const dbCode = `import { Database } from "bun:sqlite";

const db = new Database("urls.db");

db.exec(\`
  CREATE TABLE IF NOT EXISTS links (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    short_code TEXT UNIQUE NOT NULL,
    long_url TEXT NOT NULL,
    clicks INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  )
\`);

export function createLink(longUrl: string, shortCode?: string): string {
  const code = shortCode || generateCode();
  const stmt = db.prepare("INSERT INTO links (short_code, long_url) VALUES (?, ?)");
  stmt.run(code, longUrl);
  return code;
}

export function getLink(shortCode: string): { long_url: string; clicks: number } | null {
  const stmt = db.prepare("SELECT long_url, clicks FROM links WHERE short_code = ?");
  return stmt.get(shortCode) as any || null;
}

export function incrementClicks(shortCode: string): void {
  const stmt = db.prepare("UPDATE links SET clicks = clicks + 1 WHERE short_code = ?");
  stmt.run(shortCode);
}

export function getAllLinks(): Array<{
  short_code: string;
  long_url: string;
  clicks: number;
  created_at: string;
}> {
  const stmt = db.prepare("SELECT short_code, long_url, clicks, created_at FROM links ORDER BY created_at DESC");
  return stmt.all() as any;
}

function generateCode(): string {
  const chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
  let code = "";
  for (let i = 0; i < 6; i++) {
    code += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  // Check collision and retry
  const exists = db.prepare("SELECT 1 FROM links WHERE short_code = ?").get(code);
  if (exists) return generateCode();
  return code;
}

export { db };
`;

